UPDATE words SET example_en_2 = 'The trip became a personal odyssey of self-discovery.', example_ko_2 = '그 여행은 자기 발견의 개인적인 오디세이가 됐어요.', example_en_3 = 'Homer''s Odyssey inspired a generation of travellers.', example_ko_3 = '호머의 오디세이는 한 세대의 여행자들에게 영감을 줬어요.', example_en_4 = 'Her memoir describes a two-year odyssey across six continents.', example_ko_4 = '그녀의 회고록은 6개 대륙에 걸친 2년간의 오디세이를 담고 있어요.', example_en_5 = 'The journey was less a holiday and more an odyssey.', example_ko_5 = '그 여정은 휴가라기보다는 오디세이에 가까웠어요.' WHERE id = 'w_travel_C1_01';
