UPDATE words SET example_en_2 = 'The rate rose by twenty-five basis points yesterday.', example_ko_2 = '어제 금리가 25bp 상승했어요.', example_en_3 = 'One basis point equals one hundredth of a percent.', example_ko_3 = '1bp는 0.01%와 같아요.', example_en_4 = 'The spread narrowed by fifty basis points after the announcement.', example_ko_4 = '발표 후 스프레드가 50bp 축소됐어요.', example_en_5 = 'Basis point moves are closely watched in bond markets.', example_ko_5 = 'bp 움직임은 채권 시장에서 면밀히 주시돼요.' WHERE id = 'w_work_C2_26';

