UPDATE words SET example_en_2 = 'The force majeure clause was triggered by the earthquake.', example_ko_2 = '지진으로 인해 불가항력 조항이 발동됐어요.', example_en_3 = 'Force majeure excused performance during the lockdown.', example_ko_3 = '봉쇄 기간 동안 불가항력으로 이행이 면제됐어요.', example_en_4 = 'Courts narrowly interpret force majeure in commercial contracts.', example_ko_4 = '법원은 상업 계약의 불가항력을 엄격하게 해석해요.', example_en_5 = 'Both parties agreed to expand the force majeure definition.', example_ko_5 = '양측이 불가항력의 정의를 확대하기로 합의했어요.' WHERE id = 'w_work_C2_28';

