UPDATE words SET example_en_2 = 'The borrower signed a promissory note for the full amount.', example_ko_2 = '차입자가 전액에 대한 약속 어음에 서명했어요.', example_en_3 = 'A promissory note is legally binding and enforceable.', example_ko_3 = '약속 어음은 법적 구속력이 있고 집행 가능해요.', example_en_4 = 'The promissory note carried an annual interest rate of five percent.', example_ko_4 = '약속 어음의 연이율은 5%였어요.', example_en_5 = 'We accepted a promissory note instead of immediate payment.', example_ko_5 = '즉각적인 지불 대신 약속 어음을 수락했어요.' WHERE id = 'w_work_C2_31';

