UPDATE words SET example_en_2 = 'Subrogation allows the insurer to sue the at-fault party.', example_ko_2 = '대위권은 보험사가 과실 있는 당사자를 소송할 수 있게 해요.', example_en_3 = 'The insurer waived its subrogation rights in the agreement.', example_ko_3 = '보험사가 계약서에서 대위권을 포기했어요.', example_en_4 = 'Subrogation prevents the insured from recovering twice.', example_ko_4 = '대위권은 피보험자가 이중으로 보상받는 것을 방지해요.', example_en_5 = 'The concept of subrogation is central to insurance law.', example_ko_5 = '대위의 개념은 보험법의 핵심이에요.' WHERE id = 'w_work_C2_34';

